    val testState by viewModel.testState.collectAsState()

    var email by remember { mutableStateOf("test@example.com") }
    var password by remember { mutableStateOf("password123") }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.Center,
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        // Debug Text
        Text(
            text = "DEBUG - BASE_URL: http://10.0.2.2:8000/api/",
            color = Color.Gray,
            modifier = Modifier.padding(bottom = 32.dp)
        )

        OutlinedTextField(
            value = email,
            onValueChange = { email = it },
            label = { Text("Email") },
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(8.dp))

        OutlinedTextField(
            value = password,
            onValueChange = { password = it },
            label = { Text("Password") },
            visualTransformation = PasswordVisualTransformation(),
            modifier = Modifier.fillMaxWidth()
        )

        Spacer(modifier = Modifier.height(16.dp))

        Button(
            onClick = {
                viewModel.login(LoginRequest(email, password))
            },
            modifier = Modifier.fillMaxWidth(),
            enabled = loginState !is UiState.Loading
        ) {
            Text("Login API Test")
        }

        Spacer(modifier = Modifier.height(16.dp))

        Button(
            onClick = {
                viewModel.testEndpoints()
            },
            modifier = Modifier.fillMaxWidth(),
            enabled = testState !is UiState.Loading
        ) {
            Text("Test Authorized Endpoints")
        }

        Spacer(modifier = Modifier.height(16.dp))

        Button(
            onClick = {
                viewModel.testHikingSessions()
            },
            modifier = Modifier.fillMaxWidth(),
            enabled = testState !is UiState.Loading
        ) {
            Text("Test Hiking Sessions & Navigation")
        }

        Spacer(modifier = Modifier.height(16.dp))

        Button(
            onClick = {
                viewModel.testWeather()
            },
            modifier = Modifier.fillMaxWidth(),
            enabled = testState !is UiState.Loading
        ) {
            Text("Test Weather API")
        }

        Spacer(modifier = Modifier.height(32.dp))

        // Observe UiState
        when (val state = loginState) {
            is UiState.Idle -> { }
            is UiState.Loading -> {
                CircularProgressIndicator()
