                    text = "Login Error: " + state.message,
                    color = Color.Red
                )
            }
        }

        Spacer(modifier = Modifier.height(16.dp))

        when (val state = testState) {
            is UiState.Idle -> { }
            is UiState.Loading -> {
                CircularProgressIndicator()
            }
            is UiState.Success -> {
                Text(
                    text = state.data,
                    color = Color.Green
                )
            }
            is UiState.Error -> {
                Text(
                    text = state.message,
                    color = Color.Red
                )
